import { describe, it, expect, beforeEach, afterEach, vi } from 'vitest';
import { mkdirSync, rmSync, readFileSync, writeFileSync, existsSync } from 'node:fs';
import { join } from 'node:path';
import { tmpdir } from 'node:os';
import { mockCommonBasic } from '../fixtures/mock-common.js';

// Mock paths module to control telemetry directory
const testDir = join(tmpdir(), `ork-telemetry-test-${process.pid}`);

vi.mock('../../lib/paths.js', () => ({
  getPluginDataDir: () => testDir,
  getProjectDir: () => testDir,
}));

vi.mock('../../lib/common.js', () => mockCommonBasic({
  logHook: () => {},
}));

import {
  getTelemetryDir,
  getTelemetryPath,
  writeTelemetryEvent,
  rotateTelemetryIfNeeded,
  cleanOldTelemetryFiles,
} from '../../lib/telemetry-jsonl.js';
import { createTestContext } from '../fixtures/test-context.js';

let testCtx: ReturnType<typeof createTestContext>;
describe('Telemetry JSONL Sink', () => {
  beforeEach(() => {
    testCtx = createTestContext();
    // Create fresh test directory
    mkdirSync(join(testDir, 'telemetry'), { recursive: true });
  });

  afterEach(() => {
    // Clean up test directory
    try {
      rmSync(testDir, { recursive: true, force: true });
    } catch {
      // Ignore cleanup errors
    }
  });

  describe('getTelemetryDir', () => {
    it('resolves to PLUGIN_DATA/telemetry', () => {
      expect(getTelemetryDir()).toBe(join(testDir, 'telemetry'));
    });
  });

  describe('getTelemetryPath', () => {
    it('resolves to events.jsonl in telemetry dir', () => {
      expect(getTelemetryPath()).toBe(join(testDir, 'telemetry', 'events.jsonl'));
    });
  });

  describe('writeTelemetryEvent', () => {
    it('appends a JSON line to events.jsonl', async () => {
      const payload = { event: 'PreToolUse', session_id: 'test-123', data: { tool_name: 'Bash' } };

      writeTelemetryEvent(payload);

      // Wait for async appendFile to complete
      await new Promise(r => setTimeout(r, 50));

      const content = readFileSync(getTelemetryPath(), 'utf8');
      const lines = content.trim().split('\n');
      expect(lines).toHaveLength(1);
      expect(JSON.parse(lines[0])).toEqual(payload);
    });

    it('appends multiple events as separate lines', async () => {
      writeTelemetryEvent({ event: 'PreToolUse', n: 1 });
      writeTelemetryEvent({ event: 'PostToolUse', n: 2 });
      writeTelemetryEvent({ event: 'SessionEnd', n: 3 });

      await new Promise(r => setTimeout(r, 100));

      const content = readFileSync(getTelemetryPath(), 'utf8');
      const lines = content.trim().split('\n');
      expect(lines).toHaveLength(3);
      // appendFile is async — order may vary, so check set membership
      const events = lines.map(l => JSON.parse(l).event).sort();
      expect(events).toEqual(['PostToolUse', 'PreToolUse', 'SessionEnd']);
    });

    it('creates telemetry directory if it does not exist', async () => {
      // Remove the directory
      rmSync(join(testDir, 'telemetry'), { recursive: true, force: true });
      expect(existsSync(join(testDir, 'telemetry'))).toBe(false);

      writeTelemetryEvent({ event: 'test' });
      await new Promise(r => setTimeout(r, 50));

      expect(existsSync(getTelemetryPath())).toBe(true);
    });

    it('produces valid JSONL (each line is valid JSON)', async () => {
      const events = [
        { event: 'PreToolUse', data: { tool_name: 'Bash', tool_input: { command: 'ls' } } },
        { event: 'PostToolUse', data: { tool_name: 'Write', tool_output: { _raw: 'ok' } } },
        { event: 'SubagentStart', data: { agent_type: 'Explore', agent_id: 'a1' } },
      ];

      for (const e of events) writeTelemetryEvent(e);
      await new Promise(r => setTimeout(r, 50));

      const content = readFileSync(getTelemetryPath(), 'utf8');
      const lines = content.trim().split('\n');
      for (const line of lines) {
        expect(() => JSON.parse(line)).not.toThrow();
      }
    });
  });

  describe('rotateTelemetryIfNeeded', () => {
    it('does nothing when file is under 10MB', async () => {
      writeFileSync(getTelemetryPath(), '{"event":"test"}\n');

      await rotateTelemetryIfNeeded();

      expect(existsSync(getTelemetryPath())).toBe(true);
      // No rotated files
      const { readdirSync } = await import('node:fs');
      const files = readdirSync(join(testDir, 'telemetry'));
      expect(files.filter(f => f !== 'events.jsonl')).toHaveLength(0);
    });

    it('rotates file when it exceeds 10MB', async () => {
      // Create a file > 10MB
      const bigLine = JSON.stringify({ event: 'test', data: 'x'.repeat(1000) }) + '\n';
      const lines = Math.ceil((10 * 1024 * 1024 + 1) / bigLine.length);
      writeFileSync(getTelemetryPath(), bigLine.repeat(lines));

      await rotateTelemetryIfNeeded();

      // Active file should be gone (renamed)
      expect(existsSync(getTelemetryPath())).toBe(false);

      // A rotated file should exist
      const { readdirSync } = await import('node:fs');
      const files = readdirSync(join(testDir, 'telemetry'));
      const rotated = files.filter(f => f.startsWith('events.') && f !== 'events.jsonl');
      expect(rotated.length).toBe(1);
      expect(rotated[0]).toMatch(/^events\.\d{8}T\d{6}\.jsonl$/);
    });

    it('does nothing when file does not exist', async () => {
      // No file — should not throw
      await expect(rotateTelemetryIfNeeded()).resolves.toBeUndefined();
    });
  });

  describe('cleanOldTelemetryFiles', () => {
    it('removes rotated files older than 7 days', async () => {
      const telDir = join(testDir, 'telemetry');
      const oldFile = join(telDir, 'events.20260301T120000.jsonl');
      const recentFile = join(telDir, 'events.20260402T120000.jsonl');

      writeFileSync(oldFile, '{"event":"old"}\n');
      writeFileSync(recentFile, '{"event":"recent"}\n');

      // Set old file's mtime to 10 days ago
      const { utimes } = await import('node:fs/promises');
      const tenDaysAgo = new Date(Date.now() - 10 * 24 * 60 * 60 * 1000);
      await utimes(oldFile, tenDaysAgo, tenDaysAgo);

      await cleanOldTelemetryFiles();

      expect(existsSync(oldFile)).toBe(false);
      expect(existsSync(recentFile)).toBe(true);
    });

    it('never deletes the active events.jsonl', async () => {
      writeFileSync(getTelemetryPath(), '{"event":"active"}\n');

      // Set mtime to 30 days ago
      const { utimes } = await import('node:fs/promises');
      const thirtyDaysAgo = new Date(Date.now() - 30 * 24 * 60 * 60 * 1000);
      await utimes(getTelemetryPath(), thirtyDaysAgo, thirtyDaysAgo);

      await cleanOldTelemetryFiles();

      // Active file must survive regardless of age
      expect(existsSync(getTelemetryPath())).toBe(true);
    });

    it('handles missing telemetry directory gracefully', async () => {
      rmSync(join(testDir, 'telemetry'), { recursive: true, force: true });
      await expect(cleanOldTelemetryFiles()).resolves.toBeUndefined();
    });
  });
});
